// Parse and validate input
const body = $input.first().json.body;

// Required: event ID
if (!body.eventId && !body.id && !body.googleEventId) {
  throw new Error('ID на събитието е задължително');
}

const eventId = body.eventId || body.id || body.googleEventId;

// Map color names to Google Calendar colorId (1-11)
const colorMap = {
  'green': '10', 'blue': '9', 'red': '11', 'yellow': '5',
  'purple': '3', 'orange': '6', 'pink': '4', 'gray': '8'
};

const statusLabels = { 'pending': 'Чакащ', 'confirmed': 'Потвърден', 'completed': 'Завършен' };
const statusVal = body.status || 'confirmed';
const statusLabel = statusLabels[statusVal] || 'Потвърден';

// Reminder flag (if provided)
const hasReminderField = (body.sendReminder !== undefined && body.sendReminder !== null);
const sendReminder = body.sendReminder === true || body.sendReminder === 'true';

// Build update fields
const updateFields = {};

if (body.date && body.startTime) {
  const duration = body.duration || 30;
  const startDate = new Date(`${body.date}T${body.startTime}:00`);
  const endDate = new Date(startDate.getTime() + duration * 60 * 1000);
  const endTime = body.endTime || `${String(endDate.getHours()).padStart(2, '0')}:${String(endDate.getMinutes()).padStart(2, '0')}`;

  updateFields.startDateTime = `${body.date}T${body.startTime}:00`;
  updateFields.endDateTime = `${body.date}T${endTime}:00`;
}

if (body.patientName) {
  let name = body.patientName.replace(/^⏳\s*/, '');
  updateFields.summary = statusVal === 'pending' ? '⏳ ' + name : name;
}

// Build description with status line AND reminder tag
let description;
if (body.description) {
  // Caller provided full description — clean known tags then re-append
  description = body.description
    .replace(/📋\s*Статус:.*\n?/gi, '')
    .replace(/🔔\s*Напомняне:.*\n?/gi, '')
    .trim();
  description += '\n📋 Статус: ' + statusLabel;
  if (hasReminderField) {
    description += '\n🔔 Напомняне: ' + (sendReminder ? 'ДА' : 'НЕ');
  }
} else {
  // Build description from individual fields
  description = '';
  if (body.patientPhone) description += `📞 Тел: ${body.patientPhone}\n`;
  if (body.patientEmail) description += `✉️ Имейл: ${body.patientEmail}\n`;
  if (body.procedure) description += `🦷 Процедура: ${body.procedure}\n`;
  description += `📋 Статус: ${statusLabel}\n`;
  if (hasReminderField) {
    description += `🔔 Напомняне: ${sendReminder ? 'ДА' : 'НЕ'}\n`;
  }
  if (body.notes) description += `📝 Бележки: ${body.notes}\n`;
}
updateFields.description = description.trim();

const statusColorDefaults = { 'pending': 'yellow', 'completed': 'gray', 'confirmed': 'green' };
const effectiveColor = body.colorId || statusColorDefaults[statusVal] || 'green';
updateFields.colorId = colorMap[effectiveColor] || colorMap['green'];

return [{
  json: {
    eventId: eventId,
    updateFields: updateFields,
    status: statusVal,
    sendReminder: sendReminder,
    originalData: body
  }
}];

// Get updated event details
const event = $input.first().json;
const prevData = $('Prepare Update Data').first().json;

// Helper function to convert to Europe/Sofia timezone
function toSofiaTime(isoString) {
  if (!isoString) return null;
  const d = new Date(isoString);
  const options = {
    timeZone: 'Europe/Sofia',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  };
  const formatter = new Intl.DateTimeFormat('en-CA', options);
  const parts = formatter.formatToParts(d);
  const getPart = (type) => parts.find(p => p.type === type)?.value || '00';
  return {
    date: `${getPart('year')}-${getPart('month')}-${getPart('day')}`,
    time: `${getPart('hour')}:${getPart('minute')}`
  };
}

// Parse times - CONVERT TO SOFIA TIMEZONE
const startDateTime = event.start?.dateTime || event.start?.date;
const endDateTime = event.end?.dateTime || event.end?.date;
let startDate, startTime, endTime;

if (startDateTime) {
  const startSofia = toSofiaTime(startDateTime);
  const endSofia = toSofiaTime(endDateTime);
  startDate = startSofia.date;
  startTime = startSofia.time;
  endTime = endSofia.time;
}

return [{
  json: {
    id: event.id,
    googleEventId: event.id,
    title: event.summary,
    date: startDate,
    startTime: startTime,
    endTime: endTime,
    description: event.description,
    status: prevData.status || 'confirmed',
    htmlLink: event.htmlLink,
    updated: event.updated
  }
}];
